# ANTI-PATTERN: Tightly coupled, hard to test
class BattingPerformanceAnalyzer:
    def analyze(self, batsman_stats):
        # Data prep mixed with logic
        cleaned = self._clean_data(batsman_stats)
        avg = sum(cleaned) / len(cleaned)

        # Direct dependencies everywhere
        logger.log(f"Average: {avg}")
        email_service.send(f"Stats: {avg}")
        database.save({"average": avg})

        return avg

# BEST PRACTICE: Pipeline + Strategy Pattern
from abc import ABC, abstractmethod

class BattingAnalysisPipeline:
    def __init__(self, transformer, analyzer, notifier):
        self.transformer = transformer
        self.analyzer = analyzer
        self.notifier = notifier

    def execute(self, raw_stats):
        # Clear separation of concerns
        transformed = self.transformer.clean(raw_stats)
        result = self.analyzer.compute(transformed)
        self.notifier.notify(result)
        return result

class StatsAnalyzer(ABC):
    @abstractmethod
    def compute(self, data):
        pass

class AverageAnalyzer(StatsAnalyzer):
    def compute(self, data):
        return sum(data) / len(data)

class MedianAnalyzer(StatsAnalyzer):
    def compute(self, data):
        return sorted(data)[len(data)//2]

# Usage: Swap analyzers without touching pipeline
pipeline = BattingAnalysisPipeline(
    transformer=DataTransformer(),
    analyzer=AverageAnalyzer(),  # or MedianAnalyzer()
    notifier=EmailNotifier()
)
